    m = M(k); n = N(k);
    disp(['n = ' num2str(n)]);
    [r ISL] = aperplotsiso(golomb(n));
    MFGolomb(k) = n^2 / ISL;
    [r ISL] = aperplotsiso(cansiso(n,golomb(n)));
    MFCANGolomb(k) = n^2 / ISL;
    [r ISL] = aperplotsiso(mseq(m));
    MFMseq(k) = n^2 / ISL;
